const ticket = $json;
const taskIdMatch = String(ticket.headline || ticket.title || ticket.description || '').match(/TASK-[A-Z0-9-]+/);
return [{ json: {
  ref: 'main',
  inputs: {
    ticket_id: String(ticket.id),
    task_id: taskIdMatch ? taskIdMatch[0] : String(ticket.id),
    task_title: String(ticket.headline || ticket.title || ''),
    task_body: String(ticket.description || ticket.body || ''),
    target_repo: ticket.target_repo || 'ZeroGeeTH/salah-time',
    leantime_url: 'https://project.cocofriday.com/api/jsonrpc/'
  }
}}];
